INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (1, 'Pan Arab Free Trade Area / Greater Arab Free Trade Area (GAFTA)', 'agreement', 'regional', 'Arab', 'Arab League members', '2005', 'active', 'Arab trade facilitation and tariff elimination framework for participating Arab states.', 'Preferential/zero tariffs across many Arab markets subject to origin rules and product coverage.', 'Local value-added 40% or detailed product-specific origin rules, per GOEIC guidance.', 'GAFI / GOEIC', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'arab, gafta, pafta, origin, customs', 0, 1774951319.7847476, 1774951319.7847483);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (2, 'COMESA', 'agreement', 'regional', 'Africa', 'COMESA member states', '1998', 'active', 'Egypt is a COMESA member and grants customs exemptions for qualifying goods with COMESA certificates of origin.', 'Duty exemptions on qualifying goods; access to Eastern and Southern African markets.', 'Reference origin threshold around 45% value added per GAFI summary; confirm product-specific rules before shipment.', 'GAFI / GOEIC', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'comesa, africa, origin, certificate', 0, 1774951319.787434, 1774951319.787435);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (3, 'Agadir Agreement', 'agreement', 'regional', 'Arab / Mediterranean', 'Egypt, Jordan, Morocco, Tunisia (+ later accessions noted by EU)', '2006', 'active', 'Free trade arrangement linking Egypt with Jordan, Morocco, and Tunisia, with cumulation benefits tied to Euro-Med rules.', 'Full tariff and non-tariff relief for covered industrial and agricultural products; cumulation helps access wider Euro-Med supply chains.', 'Detailed rules with diagonal cumulation under the Euro-Med framework.', 'GOEIC / EU', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'agadir, morocco, jordan, tunisia, euromed', 0, 1774951319.7879598, 1774951319.7879603);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (4, 'EU-Egypt Association Agreement', 'agreement', 'bilateral / regional', 'Europe / Mediterranean', 'European Union', '2004', 'active', 'Creates a free-trade area for many industrial goods and facilitates trade in agricultural, processed agricultural, and fisheries products.', 'Tariff reduction/elimination across broad product groups and integration with Pan-Euro-Mediterranean origin framework.', 'Pan-Euro-Mediterranean rules of origin / EUR.1 / EUR-MED where applicable.', 'EU / GOEIC', 'https://policy.trade.ec.europa.eu/eu-trade-relationships-country-and-region/countries-and-regions/egypt_en', 'eu, europe, eur1, eurmed, pem', 0, 1774951319.7884042, 1774951319.7884047);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (5, 'Egypt-EFTA Free Trade Agreement', 'agreement', 'bilateral / regional', 'Europe', 'Switzerland, Norway, Iceland, Liechtenstein', '2007', 'active', 'Free trade framework with EFTA states for industrial goods and selected agricultural/fisheries concessions.', 'Tariff elimination on many industrial exports and preferential treatment on selected agricultural goods.', 'Detailed origin rules; EUR.1 / EUR-MED depending on shipment route and cumulation context.', 'GAFI / GOEIC', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'efta, switzerland, norway, iceland, liechtenstein', 0, 1774951319.7887688, 1774951319.7887692);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (6, 'Egypt-Türkiye Free Trade Agreement', 'agreement', 'bilateral', 'Mediterranean', 'Türkiye', '2007', 'active', 'Bilateral FTA creating phased liberalization and improved access for industrial and agricultural trade.', 'Immediate or phased customs exemptions across product lists and better integration into EU-facing supply chains.', 'Detailed preferential origin rules using EUR.1 / EUR-MED framework where applicable.', 'GAFI / GOEIC', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'turkey, türkiye, eur1, euromed', 0, 1774951319.7891, 1774951319.7891002);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (7, 'Egypt-MERCOSUR Free Trade Agreement', 'agreement', 'bilateral / bloc', 'Latin America', 'MERCOSUR countries', '2010', 'active', 'Preferential agreement supporting Egyptian access to South American markets and lower import cost for selected goods from the bloc.', 'Preferential tariff treatment for exports and imports under covered schedules.', 'Preferential origin certification required; verify product-specific schedules before quoting.', 'GAFI / GOEIC', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'mercosur, brazil, argentina, latin america', 0, 1774951319.7894218, 1774951319.7894223);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (8, 'African Continental Free Trade Area (AfCFTA)', 'agreement', 'continental', 'Africa', 'African Union participating states', '2021', 'active', 'Continental framework to expand African trade; Egypt indicated operationalization from the beginning of 2021.', 'Preferential tariffs and broader African market access under negotiated schedules.', 'AfCFTA protocol rules of origin and tariff schedules; check the AfCFTA e-tariff tool for HS-specific treatment.', 'GOEIC', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'afcfta, africa, tariff, origin', 0, 1774951319.7897415, 1774951319.789742);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (9, 'Egypt-United Kingdom Free Trade Agreement', 'agreement', 'bilateral', 'Europe', 'United Kingdom', '2021', 'active', 'Post-Brexit continuity-style framework listed by GOEIC among active preferential agreements.', 'Continuity of preferential access for covered goods with UK market routing.', 'Pan-Euro-Med style origin references/EUR.1-EUR-MED documentation as specified by official guidance.', 'GOEIC', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'uk, britain, eur1, post-brexit', 0, 1774951319.7907834, 1774951319.7907844);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (10, 'Egypt-Serbia Free Trade Agreement', 'agreement', 'bilateral', 'Europe', 'Serbia', '2025', 'active', 'GOEIC lists the Serbia agreement among Egypt’s active agreements as of the March 2026 update.', 'Preferential bilateral market access subject to the agreement schedules.', 'Detailed preferential rules and certificate requirements per GOEIC guidance.', 'GOEIC', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'serbia, bilateral, europe', 0, 1774951319.7911334, 1774951319.7911339);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (11, 'Qualified Industrial Zones (QIZ)', 'agreement', 'special access regime', 'United States / Egypt', 'United States (via designated zones)', '2004', 'active', 'Duty-free access to the US market for goods produced in approved Egyptian zones that satisfy QIZ origin requirements.', 'Duty-free access to US market for qualifying products from approved zones.', 'Requires compliance with the QIZ agreed origin content and zone conditions.', 'GAFI', 'https://www.gafi.gov.eg/English/Sectors/Pages/Trade-Agreements.aspx', 'qiz, usa, zones, origin', 0, 1774951319.79139, 1774951319.7913902);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (12, 'Generalized System of Preferences (GSP)', 'agreement', 'preference scheme', 'Global', 'Preference-granting countries', 'ongoing', 'reference', 'GOEIC lists GSP as a preference scheme; availability depends on the granting country’s program status and product coverage.', 'Potential tariff preferences where the importing country still operates GSP for Egyptian goods.', 'Program-specific rules of origin and documentary requirements.', 'GOEIC', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'gsp, scheme, preferences', 0, 1774951319.791661, 1774951319.7916613);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (13, 'GSTP - Global System of Trade Preferences', 'agreement', 'preference scheme', 'Global South', 'GSTP participating developing countries', 'ongoing', 'reference', 'GOEIC lists GSTP as a preferential trade framework among participating developing countries.', 'Potential tariff preferences for covered products among participating members.', 'Scheme-specific origin rules and certificate requirements.', 'GOEIC', 'https://www.goeic.gov.eg/en/pages/default/view/id/101/m/4-65', 'gstp, developing countries, preferences', 0, 1774951319.7919376, 1774951319.791938);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (14, 'Investment Laws & Regulations Portal', 'law', 'portal', 'Egypt', '', 'updated', 'official resource', 'Official GAFI portal aggregating Egypt investment laws, regulations, and downloadable legal texts.', 'Single official starting point for investment law references relevant to foreign investors and project setup.', '', 'GAFI', 'https://www.gafi.gov.eg/English/StartaBusiness/Laws-and-Regulations/Pages/BusinessLaws.aspx', 'investment, laws, regulations, gafi', 100, 1774951319.7922711, 1774951319.7922714);
