INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (17, 'GOEIC Laws and Decisions Portal', 'law', 'portal', 'Egypt', '', 'updated', 'official resource', 'Official GOEIC list of ministerial decisions and rules organizing import, export, origin, and trade registrations.', 'Useful searchable hub for current procedural decisions affecting exporters/importers.', '', 'GOEIC', 'https://www.goeic.gov.eg/en/laws-and-decisions/list/898', 'goeic, laws, decisions, import, export', 100, 1774951319.7929904, 1774951319.7929907);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (18, 'Import and Export Executive Decree No. 770/2005', 'law', 'decree', 'Egypt', '', '2005', 'official resource', 'Ministerial decree governing a wide range of import/export registration and procedures.', 'Key operational reference for exporter/importer compliance.', '', 'GAFI', 'https://www.gafi.gov.eg/English/StartaBusiness/Laws-and-Regulations/PublishingImages/Pages/TradeLaws/import%20and%20export.pdf', '770 2005 import export decree', 100, 1774951319.793161, 1774951319.7931612);
INSERT INTO trade_reference_items (id, title, category, item_type, region, partner_countries, effective_year, status, summary, benefits, rules_of_origin, source_org, source_url, tags, sort_order, created_at, updated_at) VALUES (19, 'Customs Law No. 207 of 2020 / Executive Regulation No. 430 of 2021', 'law', 'customs law', 'Egypt', '', '2020-2021', 'official resource', 'Core customs framework referenced by Nafeza for ACID, document submission, and shipment procedures.', 'Essential legal base for import clearance and pre-arrival cargo information workflows.', '', 'Nafeza', 'https://www.nafeza.gov.eg/en/faq/list?q=ACI', 'customs law 207 2020 regulation 430 2021 acid nafeza', 100, 1774951319.7933629, 1774951319.793363);
